import{_ as e,o as a,c as p,j as r,a as t,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const L=JSON.parse('{"title":"针匣","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/远程武器/7.系列武器/太吾绘卷兵器谱/针匣.md","filePath":"4.资源分区/7.物品与装备/2.武器/远程武器/7.系列武器/太吾绘卷兵器谱/针匣.md"}'),s={name:"4.资源分区/7.物品与装备/2.武器/远程武器/7.系列武器/太吾绘卷兵器谱/针匣.md"};function o(d,b,l,i,_,c){return a(),p("div",null,[...b[0]||(b[0]=[r("h1",{id:"针匣",tabindex:"-1"},[t("针匣 "),r("a",{class:"header-anchor",href:"#针匣","aria-label":'Permalink to "针匣"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风021")])])],-1),n('<h1 id="针匣-1" tabindex="-1">针匣 <a class="header-anchor" href="#针匣-1" aria-label="Permalink to &quot;针匣&quot;">​</a></h1><p>针匣：</p><p>本系列中的武器，如无特殊手段，皆使用运动下专业：针进行攻击。</p><p>无支线：</p><p>【蝎尾针匣】<br> 1000<br> 自然本质<br> 蝎尾针形制独特，酷似蝎尾，乃是以钢铁打造而成，虽较长针而言更为沉重，但杀伤力也更强。<br> 体积：1，造成穿刺伤害。武器伤害2L，【高速1】，一匣50根，使用后需要回收，若不回收，则永久减少针匣内针的数量。</p><p>【芙蓉针匣】<br> 550<br> 自然本质<br> 芙蓉针匣表面阳雕荷花图样，清丽动人，惟妙惟肖，匣中装有医者常用的锋针，铍针等针具，既可治病，亦能遇敌。<br> 体积：1，造成穿刺伤害。武器伤害0L，【高速3】，一匣5根，使用后需要回收，若不回收，则永久减少针匣内针的数量。</p><p>【鬼焰匣】<br> 550<br> 自然本质<br> 鬼焰匣色同鬼火，光芒闪烁，其针性质奇特，入体时若遇邪气，则中者陡升暖意；若遇正气，则中者全身恶寒。<br> 体积：1，造成穿刺伤害。武器伤害0L，【高速1】【破魔2】，一匣5根，使用后需要回收，若不回收，则永久减少针匣内针的数量。</p><p>【璃锋宝匣】<br> 600<br> 自然本质<br> 璃锋宝匣中的玉针制法复杂，针尖如同琉璃一般色彩瑰丽，流光变幻，扎入人体时不会引起分毫疼痛，是以得名。<br> 体积：1，造成穿刺伤害。武器伤害0L，【破甲2】【高速1】，一匣10根，使用后需要回收，若不回收，则永久减少针匣内针的数量。</p><p>【蜈锋匣】<br> 600<br> 自然本质<br> 蜈锋匣中的针具形如蜈脚蜂针，十分短小，一匣之中常能收纳百枚，射出时铺天盖地，如同蜈锋过境，声势惊人。<br> 体积：1，造成穿刺伤害。武器伤害0L，【高速1】【威猛2】，一匣10根，使用后需要回收，若不回收，则永久减少针匣内针的数量。</p><p>【素梅针匣】<br> D+1000<br> 自然本质 奇物<br> 素梅匣通体一色，素净无饰，针尾似梅花，小巧可爱，清新淡雅，弹指之间便可飞至数十步外。<br> 体积：1，造成穿刺伤害。武器伤害0L，一匣3根，轮回者使用素梅针匣中的针进行急救/治疗时，可以使被急救者额外恢复1点生命值（医疗点12），使用后，直接消失。</p><p>D级：</p><p>【白虎煞】<br> D+500<br> 自然本质<br> 正所谓：“庚金带煞，刚健为最。”，白虎主西方七宿，性属庚金。白虎煞锐气逼人，射出时清音肃肃，宛如虎啸，故而得名。<br> 体积：1，造成穿刺伤害。武器伤害3L，【高速1】，具有【贯穿】特性，一匣500根，每次射完后都将在第二天重新生成500根。</p><p>【玉虬冰针】<br> D+500<br> 特异本质<br> 玉虬冰匣刻有虬龙纹样，质地通透，入手如冰。其针破空之声好似龙吟，一旦入体，便会化为寒气，遍寻不见。<br> 体积：1，造成穿刺伤害。武器伤害3L，使用此针对敌方单位造成伤害时，会附带1点不可豁免的冻结点数（毒素来源）。</p><p>【独灵针匣】<br> D+500<br> 特异本质<br> 独灵针匣意为天地灵气之独钟，必以生于风水宝地上的灵木方可制成，其针应天地之气而生，故能自行探查病灶，奇异非常。<br> 体积：1，造成穿刺伤害。武器伤害3L，具有【法破】特性，一匣500根，每次射完后都将在第二天重新生成500根。</p><p>【幽藏鬼须匣】<br> D+500<br> 特异本质<br> 幽藏鬼须匣中的木针细愈发丝，若隐若现，故名“鬼须”；其色幽暗，难以察觉，故谓“幽藏”；此针射出时无声无息，唯有武学高手能察其踪迹。<br> 体积：1，造成穿刺伤害。武器伤害3L，此针攻击时具有D级措手不及特性，一匣500根，每次射完后都将在第二天重新生成500根。</p><p>C级：</p><p>【五邪针】<br> C+1000<br> 特异本质<br> 五邪者，虚、实、微、贼、正也，五行不调，故而生邪。此匣以精金铸就，其针可正五邪，亦可乱五行之气，活人毁人只在一念之间。<br> 体积：1，造成穿刺伤害。武器伤害8L，使用此针对友方单位进行生命值回复时，可以使该目标额外获得1点异常点治疗（医疗点24），对敌人造成伤害时具有【劣化1】特性。</p><p>【逆元针】<br> C+1000<br> 特异本质<br> 正所谓：“物极必反，命日环流”。逆元匣因可逆转人物体内元气运行方向而得名，中针者初时只感精力充沛，但少顷便觉血海翻涌，元气衰散。<br> 体积：1，造成穿刺伤害。武器伤害8L，【高速3】【破甲1】使用此针具有【毁灭】特性，对敌人造成伤害时附带相等的亢奋点数（创伤来源）。</p><p>【九灵辟邪针】<br> C+1250<br> 特异本质<br> 相传昆仑山有九灵之馆，上接璇玑之轮，下在太宫之中，乃王母所治。九灵辟邪匣上刻有九种灵物，光彩照人，可使邪祟辟易。<br> 体积：1，造成穿刺伤害。武器伤害6L，具有5点破魔，并有【法破】【9加骰】特性。</p><p>B级：</p><p>【阴阳乱】<br> B+2000<br> 特异本质<br> 书云：“清阳出上窍，浊阴出下窍”。阴阳乱中共藏有阴、阳两种金针，阴针气浊，阳针气清，使用者若以浊者攻上，清者攻下，便可令人阴阳颠倒，表里相攻。<br> 体积：1，造成穿刺伤害。武器伤害11L，6破魔，并具有【幻灭】特性，使用这个针攻击的时候具有8加骰以及3点附加成功。</p><p>【青女针】<br> B+2000<br> 特异本质<br> 相传青女乃霜雪之神，居青宵。此匣以灵玉制成，其中玉针一旦射出，四周便会寒如六月飞雪，如同“青女剪冰，霜雪俱降”。<br> 体积：1，武器伤害15L，该武器具有5点破魔，使用该武器攻击时，附带相等的冻结点数（诅咒来源）。使用本武器时可以再次以气形态攻击一次，两次攻击取优计算最后成功数。</p><hr><p>Copyright ? 2024 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',24)])])}const f=e(s,[["render",o]]);export{L as __pageData,f as default};
